defmodule Auth.TokenStore do
  @moduledoc """
  ETS-backed token store for fast lookups with automatic expiry.
  Stores only hashed tokens for security.
  """

  use GenServer

  @table_name :auth_tokens
  @cleanup_interval :timer.minutes(5)

  # Client API

  def start_link(opts \\ []) do
    GenServer.start_link(__MODULE__, opts, name: __MODULE__)
  end

  @spec store_token(String.t(), String.t(), map(), pos_integer()) :: :ok
  def store_token(raw_token, token_type, metadata \\ %{}, ttl_seconds \\ 86_400) do
    hashed = Auth.TokenGenerator.hash_token(raw_token)
    expires_at = System.system_time(:second) + ttl_seconds

    entry = %{
      hash: hashed,
      type: token_type,
      metadata: metadata,
      created_at: System.system_time(:second),
      expires_at: expires_at
    }

    :ets.insert(@table_name, {hashed, entry})
    :ok
  end

  @spec lookup_token(String.t()) :: {:ok, map()} | {:error, :not_found} | {:error, :expired}
  def lookup_token(raw_token) do
    hashed = Auth.TokenGenerator.hash_token(raw_token)
    now = System.system_time(:second)

    case :ets.lookup(@table_name, hashed) do
      [{^hashed, %{expires_at: expires_at} = entry}] when expires_at > now ->
        {:ok, entry}

      [{^hashed, _expired}] ->
        :ets.delete(@table_name, hashed)
        {:error, :expired}

      [] ->
        {:error, :not_found}
    end
  end

  @spec revoke_token(String.t()) :: :ok
  def revoke_token(raw_token) do
    hashed = Auth.TokenGenerator.hash_token(raw_token)
    :ets.delete(@table_name, hashed)
    :ok
  end

  # Server callbacks

  @impl true
  def init(_opts) do
    table = :ets.new(@table_name, [:set, :public, :named_table, read_concurrency: true])
    schedule_cleanup()
    {:ok, %{table: table}}
  end

  @impl true
  def handle_info(:cleanup, state) do
    cleanup_expired_tokens()
    schedule_cleanup()
    {:noreply, state}
  end

  defp schedule_cleanup do
    Process.send_after(self(), :cleanup, @cleanup_interval)
  end

  defp cleanup_expired_tokens do
    now = System.system_time(:second)

    :ets.foldl(
      fn {key, %{expires_at: expires_at}}, acc ->
        if expires_at <= now do
          :ets.delete(@table_name, key)
        end

        acc
      end,
      :ok,
      @table_name
    )
  end
end

